using UnityEngine;
using UnityEngine.Tilemaps;

public class TilemapExample : MonoBehaviour
{
    public Tilemap tilemap;
    public TileBase grassTile;
    public TileBase dirtTile;
    public TileBase stoneTile;

    void Start()
    {
        if (tilemap == null)
        {
            tilemap = GetComponent<Tilemap>();
        }

        if (tilemap == null)
        {
            Debug.LogError("Tilemap is null!");
            return;
        }

        // Clear existing tiles
        tilemap.ClearAllTiles();

        // Build a simple level
        BuildLevel();

        Debug.Log("Tilemap built!");
    }

    void BuildLevel()
    {
        // Ground (y = 0)
        for (int x = -5; x <= 5; x++)
        {
            Vector3Int pos = new Vector3Int(x, 0, 0);
            tilemap.SetTile(pos, grassTile);
        }

        // Walls (x = -5 and x = 5)
        for (int y = 1; y <= 3; y++)
        {
            tilemap.SetTile(new Vector3Int(-5, y, 0), stoneTile);
            tilemap.SetTile(new Vector3Int(5, y, 0), stoneTile);
        }

        // Platforms
        tilemap.SetTile(new Vector3Int(-3, 2, 0), dirtTile);
        tilemap.SetTile(new Vector3Int(-2, 2, 0), dirtTile);
        tilemap.SetTile(new Vector3Int(-1, 2, 0), dirtTile);

        tilemap.SetTile(new Vector3Int(2, 3, 0), dirtTile);
        tilemap.SetTile(new Vector3Int(3, 3, 0), dirtTile);
        tilemap.SetTile(new Vector3Int(4, 3, 0), dirtTile);
    }

    // Example: Set tile at position
    public void SetTile(Vector3Int position, TileBase tile)
    {
        if (tilemap != null)
        {
            tilemap.SetTile(position, tile);
        }
    }

    // Example: Get tile at position
    public TileBase GetTile(Vector3Int position)
    {
        if (tilemap != null)
        {
            return tilemap.GetTile(position);
        }
        return null;
    }

    // Example: Clear tile at position
    public void ClearTile(Vector3Int position)
    {
        if (tilemap != null)
        {
            tilemap.SetTile(position, null);
        }
    }

    // Example: Check if tile exists
    public bool HasTile(Vector3Int position)
    {
        if (tilemap != null)
        {
            return tilemap.GetTile(position) != null;
        }
        return false;
    }

    // Example: Clear all tiles
    public void ClearAll()
    {
        if (tilemap != null)
        {
            tilemap.ClearAllTiles();
        }
    }
}

